1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (isAlive: boolean, liveNeighbors: number): boolean =>
15	  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
16	
17	export function nextGeneration(liveCells: Cell[]): Cell[] {
18	  const liveKeys = new Set(liveCells.map(cellKey));
19	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
20	
21	  for (const cell of liveCells) {
22	    for (const neighbor of neighborsOf(cell)) {
23	      const key = cellKey(neighbor);
24	      const previousCount = neighborCounts.get(key)?.count ?? 0;
25	      neighborCounts.set(key, { cell: neighbor, count: previousCount + 1 });
26	    }
27	  }
28	
29	  const survivors: Cell[] = [];
30	  for (const [key, { cell, count }] of neighborCounts) {
31	    if (survives(liveKeys.has(key), count)) {
32	      survivors.push(cell);
33	    }
34	  }
35	
36	  return survivors;
37	}
